ruleContent.replaceRegex:
@js:
var f=String(src).match(/url\('([^']+)'\) format\('truetype'\)/);
if (f) {
    var f1 = java.queryTTF("https:"+f[1])
    var f2 = java.queryBase64TTF("")
    java.replaceFont(result, f1, f2)
}else{
    result
}

ruleBookInfo.name:
@js:j=String(book.customIntro).match(/^\{((?:[原单动静直转全跳逆字图]|\[[^\[\]]+\]|\d+#[^#]+#)+)\}/);
u=''+java.get("sz");
key=String(u?j?j[1]+u:u:j?j[1]:'');

r=org.jsoup.Jsoup.parse(result);
r.select("script,noscript,style,head>:not(meta),footer,[class~=^foot],[id~=^foot],a:has(>:last-child:matchesOwn(^分类$))").remove();

n=String(book.name);

m=String(r).replace(/(&nbsp;)+/g," ");

y=r.select("[property~=title$|name$][content~=^[^<?{]]");
if(y.size()){c=y.eachAttr("content")
}else c=r.select("h1,h2,strong").eachText();

for(x=0;x<c.size();x++)if(
(y=""+c.get(x))&&n.indexOf(y)+1
){n=String(y);break;}

if((x=r.select("[property$=author]")
).size()){
x=String(x.attr("content")).replace(/^作\s*[者家][\s:：]*|(?!^)[/／｜|，,\s][^⚙️]*$/,"")
}else{
x=m.match(/>\s*([^>]+?)(?:\s*<\/[a-z]+>\s*|\s+)著\s*<|[\s\[\];?!,.()、，；？！。…─（）［］〖〗【】>《》](?:小说|漫画)?作\s*者(?![^>]+->)(?:[:：\s]|<[^it\/][^>]*>|<\/[^>]+>)+([^\s<">,，/／｜|]+)/);
x=x?x[1]?x[1]:x[2]:(x=r.select("#author,.author"),x.size()?String(x.first().text()).replace(/(?!^)[/／｜|，,\s][^⚙️]*$/,""):"")}

